/**
 * @param {number[]} nums
 * @param {number} target
 * @return {number}
 */
function solve(nums, target) {
    const n = nums.length;

    // Total XOR sum of all elements
    let totalXOR = 0;
    for (const num of nums) {
        totalXOR ^= num;
    }

    // We are looking for a subset whose XOR sum is target.
    // Let S be the set of remaining elements, and R be the set of removed elements.
    // XOR(S) = target.
    // XOR(S) ^ XOR(R) = totalXOR.
    // target ^ XOR(R) = totalXOR.
    // XOR(R) = target ^ totalXOR.

    // We want to minimize the number of removed elements, |R|.
    // This is equivalent to maximizing the number of kept elements, |S|, where |S| = n - |R|.

    // If the target can be achieved by the full set, removed count is 0.
    if (totalXOR === target) {
        return 0;
    }

    // We need to find a subset R (the removed elements) such that:
    // 1. XOR(R) = requiredXOR, where requiredXOR = target ^ totalXOR
    // 2. The size of R is minimized.

    const requiredXOR = target ^ totalXOR;

    // Since N is small (<= 40), we can use meet-in-the-middle or dynamic programming/subset enumeration.
    // Given the constraints (N<=40), O(2^N) is too slow. O(2^(N/2)) might work.

    // Meet-in-the-Middle approach (Splitting N into N/2 and N - N/2)
    const n1 = Math.floor(n / 2);
    const n2 = n - n1;

    // Map to store results for the first half: {xor_sum: min_count}
    const map1 = new Map();
    map1.set(0, 0); // XOR sum 0 can be achieved by removing 0 elements

    // Generate all subset XOR sums for the first half
    for (let i = 0; i < n1; i++) {
        const num = nums[i];
        const updates = new Map();

        for (const [currentXOR, count] of map1.entries()) {
            const newXOR = currentXOR ^ num;
            const newCount = count + 1;

            // We are tracking the minimum number of elements *from the first half* 
            // that XOR up to a specific value.
            if (!updates.has(newXOR) || newCount < updates.get(newXOR)) {
                updates.set(newXOR, newCount);
            }
        }

        // Merge updates into map1, prioritizing smaller counts
        for (const [xorSum, count] of updates.entries()) {
            if (!map1.has(xorSum) || count < map1.get(xorSum)) {
                map1.set(xorSum, count);
            }
        }
    }

    // Map to store results for the second half: {xor_sum: min_count}
    const map2 = new Map();
    map2.set(0, 0); // XOR sum 0 can be achieved by removing 0 elements

    // Generate all subset XOR sums for the second half
    for (let i = 0; i < n2; i++) {
        const num = nums[n1 + i];
        const updates = new Map();

        for (const [currentXOR, count] of map2.entries()) {
            const newXOR = currentXOR ^ num;
            const newCount = count + 1;

            if (!updates.has(newXOR) || newCount < updates.get(newXOR)) {
                updates.set(newXOR, newCount);
            }
        }

        for (const [xorSum, count] of updates.entries()) {
            if (!map2.has(xorSum) || count < map2.get(xorSum)) {
                map2.set(xorSum, count);
            }
        }
    }

    // Search for the minimum total count
    let minRemovedCount = Infinity;

    // We need XOR(R) = requiredXOR.
    // We search for R = R1 U R2, where R1 is from first half, R2 from second half.
    // XOR(R1) ^ XOR(R2) = requiredXOR
    // XOR(R2) = requiredXOR ^ XOR(R1)

    for (const [xor1, count1] of map1.entries()) {
        const neededXOR2 = requiredXOR ^ xor1;

        if (map2.has(neededXOR2)) {
            const count2 = map2.get(neededXOR2);
            const totalCount = count1 + count2;
            minRemovedCount = Math.min(minRemovedCount, totalCount);
        }
    }

    if (minRemovedCount === Infinity) {
        return -1;
    }

    return minRemovedCount;
}

